#include <stdio.h>

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        if (scanf("%d", &N) != 1) return 0;
        for (int i = N; i > 0; --i) {
            for (int j = 0; j < i; ++j) putchar('*');
            putchar('\n');
        }
        if (tc != T - 1) putchar('\n');
    }
    return 0;
}

